const response = $input.first().json;
const data = $('After Clone').first().json;
let tests = { tests: [] };
try {
  const raw = response.content?.[0]?.text || '{}';
  const cleaned = raw.replace(/^```json\s*/, '').replace(/\s*```$/, '').trim();
  tests = JSON.parse(cleaned);
  if (!Array.isArray(tests.tests)) tests = { tests: [] };
} catch (e) {
  return [{ json: { ...data, status: 'error', errors: [...data.errors, `Failed to parse tests: ${e.message}`] } }];
}
return [{ json: { ...data, testsData: tests, status: 'tests_generated' } }];

const fs = require('fs');
const path = require('path');
const data = $input.first().json;
const repoDir = path.resolve(data.repoDir);
const written = [];
for (const t of data.testsData.tests || []) {
  if (!t.filePath || !t.content) continue;
  const fp = path.resolve(repoDir, t.filePath);
  if (!fp.startsWith(repoDir + path.sep)) throw new Error(`Path blocked: ${t.filePath}`);
  fs.mkdirSync(path.dirname(fp), { recursive: true });
  fs.writeFileSync(fp, t.content, 'utf8');
  written.push(t.filePath);
}
return [{ json: { ...data, testsWritten: written, status: 'tests_written' } }];

