const response = $input.first().json;
const data = $('Write Tests').first().json;
let impl = { files: [] };
try {
  const raw = response.content?.[0]?.text || '{}';
  const cleaned = raw.replace(/^```json\s*/, '').replace(/\s*```$/, '').trim();
  impl = JSON.parse(cleaned);
  if (!Array.isArray(impl.files)) impl = { files: [] };
} catch (e) {
  return [{ json: { ...data, status: 'error', errors: [...data.errors, `Failed to parse implementation: ${e.message}`] } }];
}
return [{ json: { ...data, implData: impl, status: 'implementation_generated' } }];

const fs = require('fs');
const path = require('path');
const data = $input.first().json;
const repoDir = path.resolve(data.repoDir);
const doNotTouch = data.plan.files?.doNotTouch || [];
const written = [];
for (const f of data.implData.files || []) {
  if (!f.filePath || !f.content) continue;
  if (doNotTouch.some(p => f.filePath.includes(p))) throw new Error(`Protected file blocked: ${f.filePath}`);
  const fp = path.resolve(repoDir, f.filePath);
  if (!fp.startsWith(repoDir + path.sep)) throw new Error(`Path blocked: ${f.filePath}`);
  fs.mkdirSync(path.dirname(fp), { recursive: true });
  fs.writeFileSync(fp, f.content, 'utf8');
  written.push(f.filePath);
}
return [{ json: { ...data, filesWritten: written, status: 'files_written' } }];

const cmd = $input.first().json;
const data = $('Write Files').first().json;
const passed = cmd.exitCode === 0;
const output = `EXIT_CODE: ${cmd.exitCode}

STDOUT:
${cmd.stdout}

STDERR:
${cmd.stderr}`;
return [{ json: { ...data, validationOutput: output, validationPassed: passed, status: passed ? 'validation_passed' : 'validation_failed' } }];

const fs = require('fs');
const data = $input.first().json;
const handoffPath = data.handoffPath;
fs.mkdirSync(handoffPath, { recursive: true });
fs.writeFileSync(`${handoffPath}/IMPLEMENTATION_PLAN.json`, JSON.stringify(data.plan, null, 2));
fs.writeFileSync(`${handoffPath}/validation-output.txt`, data.validationOutput || '');
fs.writeFileSync(`${handoffPath}/manifest.json`, JSON.stringify({
  featureName: data.featureName,
  status: data.validationPassed ? 'ready' : 'needs_fix',
  filesWritten: data.filesWritten,
  testsWritten: data.testsWritten,
  validationPassed: data.validationPassed,
  handoffPath
}, null, 2));
fs.writeFileSync(`${handoffPath}/claude-integration-steps.md`, `# Claude Code Integration\n\nFactory output is sandbox-only. Review files, integrate manually, run full validation, then commit.\n\n## Files\n${(data.filesWritten || []).map(f => '- ' + f).join('\n')}\n\n## Tests\n${(data.testsWritten || []).map(f => '- ' + f).join('\n')}`);
return [{ json: { ...data, finalStatus: data.validationPassed ? 'ready' : 'needs_fix', status: 'handoff_packaged' } }];
